MESSAGE_PREFIX = "[NOTIFY]"


class Notifier:
    """Base notifier that dispatches to a channel."""

    def __init__(self, name, notify_on_error=True):
        self.name = name
        self.notify_on_error = notify_on_error
        self._sent = []

    def notify(self, message):
        """Send a notification message."""
        formatted = f"{MESSAGE_PREFIX} {message}"
        self._sent.append(formatted)
        return formatted

    def history(self):
        return list(self._sent)

