from .core import Notifier


class EmailNotifier(Notifier):
    """Sends notifications via email."""

    def __init__(self, name, recipient, notify_on_error=True):
        super().__init__(name, notify_on_error=notify_on_error)
        self.recipient = recipient

    def notify(self, message):
        """Format as email and send."""
        message_id = f"email-{len(self._sent)}"
        result = super().notify(message)
        return {"message_id": message_id, "to": self.recipient, "body": result}

