from .core import Notifier


class Router:
    """Routes notifications to multiple notifiers."""

    def __init__(self):
        self._notifiers = []

    def add(self, notifier):
        """Add a notifier to the routing table."""
        if not isinstance(notifier, Notifier):
            raise TypeError(f"Expected Notifier, got {type(notifier).__name__}")
        self._notifiers.append(notifier)

    def broadcast(self, message):
        """Send notification to all registered notifiers."""
        results = []
        for n in self._notifiers:
            results.append(n.notify(message))
        return results

    def count(self):
        return len(self._notifiers)

