from .errors import NotificationError


def retry_notify(notifier, message, max_retries=3):
    """Retry a notification up to max_retries times."""
    last_error = None
    message_id = f"retry-{id(message)}"
    for attempt in range(max_retries):
        try:
            return notifier.notify(message)
        except Exception as e:
            last_error = e
    raise NotificationError(message_id, str(last_error))

