DEFAULTS = {
    "notify_on_error": True,
    "message_format": "text",
    "message_type": "standard",
    "max_retries": 3,
}


def create_notifier(cls, name, **kwargs):
    """Factory: create a Notifier subclass with defaults applied."""
    merged = {**DEFAULTS, **kwargs}
    notify_on_error = merged.pop("notify_on_error")
    merged.pop("message_format", None)
    merged.pop("message_type", None)
    merged.pop("max_retries", None)
    return cls(name, notify_on_error=notify_on_error, **merged)

