from .core import Notifier


class LoggingNotifier(Notifier):
    """Wraps a Notifier to add logging."""

    def __init__(self, inner: Notifier):
        super().__init__(inner.name, notify_on_error=inner.notify_on_error)
        self._inner = inner
        self.log = []

    def notify(self, message):
        """Log then delegate."""
        message_id = f"log-{len(self.log)}"
        self.log.append({"message_id": message_id, "content": message})
        return self._inner.notify(message)
